insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Enamorado estoy de vos', 'enamorado-estoy-de-vos', false, null, 0, '[{"role":"llamada","text":"Ésta es la pasión azul y grana,"},{"role":"coro","text":"una fiesta que no se compara,"},{"role":"llamada","text":"la que está en las buenas y en las malas,"},{"role":"coro","text":"la que la alienta de verdad."},{"role":"llamada","text":"Pero es difícil explicarlo,"},{"role":"coro","text":"con el Quito voy a todos lados,"},{"role":"llamada","text":"las cosas que hice por la Academia"},{"role":"coro","text":"por nadie lo hice jamás."},{"role":"llamada","text":"Enamorado estoy de vos,"},{"role":"coro","text":"desde hace ya mucho tiempo."},{"role":"llamada","text":"Y aunque vos no salgas campeón,"},{"role":"coro","text":"no abandonó el sentimiento."},{"role":"llamada","text":"Borracho te voy a seguir,"},{"role":"coro","text":"jamás te abandonaría."},{"role":"llamada","text":"La mafia te va a acompañar,"},{"role":"coro","text":"Quito por toda la vida!"}]'::jsonb, true, 0
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Academia eres mi vida', 'academia-eres-mi-vida', false, null, 0, '[{"role":"llamada","text":"En las buenas y en las malas,"},{"role":"coro","text":"siempre estoy,"},{"role":"llamada","text":"al Quito yo no lo dejo."},{"role":"coro","text":"Academia eres mi vida,"},{"role":"llamada","text":"siempre estoy,"},{"role":"coro","text":"te sigo porque te quiero."},{"role":"llamada","text":"Yo te voy a acompañar"},{"role":"coro","text":"aunque todo vaya mal."},{"role":"llamada","text":"La mafia te va a alentar,"},{"role":"coro","text":"nunca te va a abandonar."},{"role":"coro","text":"Solo te pido que vos"},{"role":"llamada","text":"dejes todo como yo"},{"role":"coro","text":"hasta el final."}]'::jsonb, true, 1
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Muchaaachos', 'muchachos', false, 'https://www.youtube.com/watch?v=dRuI98WVyqk', 175, '[{"role":"llamada","text":"Yo no abandono a mi equipo porque tengo identidad,"},{"role":"coro","text":"porque llevo los colores y el nombre de la ciudad."},{"role":"llamada","text":"No te lo puedo explicar"},{"role":"coro","text":"porque no vas a entender."},{"role":"llamada","text":"Tantos años que sufrimos y a tu lado seguiré."},{"role":"coro","text":"No me importa si ganás,"},{"role":"llamada","text":"no me importa si perdés,"},{"role":"coro","text":"me pongo la camiseta y otra vez te vengo a ver."},{"role":"llamada","text":"Muchachos, ahora nos volvimo'' a ilusionar,"},{"role":"coro","text":"quiero volver a primera"},{"role":"coro","text":"y ser campeón nacional."},{"role":"llamada","text":"Tu hinchada"},{"role":"coro","text":"es la que siempre te viene a ver"},{"role":"llamada","text":"la que nunca te abandona"},{"role":"coro","text":"porque somos la más fiel."}]'::jsonb, true, 2
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Se viene Quito campeón', 'se-viene-quito-campeon', false, 'https://www.youtube.com/watch?v=Ws-J40TX-1c', 56, '[{"role":"llamada","text":"Ya llega la hinchada más conocida del mundo entero,"},{"role":"coro","text":"recorriendo caminos, canchas, ciudades con muchos huevos,"},{"role":"llamada","text":"es el Deportivo Quito, fútbol candente con mucho amor,"},{"role":"coro","text":"al que todos conocemos por la Academia del Ecuador."},{"role":"llamada","text":"Eh, eh, eh, eh!"},{"role":"coro","text":"Se viene Quito campeón, Quito campeón, Quito campeón."},{"role":"llamada","text":"Se viene Quito campeón, Quito campeón, Quito campeón."},{"role":"coro","text":"Se viene Quito campeón, Quito campeón, Quito campeón."},{"role":"llamada","text":"Se viene Quito campeón, Quito campeón, Quito campeón."}]'::jsonb, true, 3
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Los colores de la capital', 'los-colores-de-la-capital', false, 'https://www.youtube.com/watch?v=JnSn9_73A2w', 179, '[{"role":"llamada","text":"Quito, tú eres mi vida,"},{"role":"coro","text":"por historia fuimos la Argentina,"},{"role":"llamada","text":"por historia somos la Academia,"},{"role":"coro","text":"por historia tú llevas la insignia de ésta gran ciudad."},{"role":"llamada","text":"Los colores de la capital"},{"role":"coro","text":"azul y rojo."},{"role":"llamada","text":"Vos cag** no hables más,"},{"role":"coro","text":"que en mi nombre está el de la ciudad."},{"role":"llamada","text":"La gloriosa AKD,"},{"role":"coro","text":"soy de vos aunque vuelva a nacer."}]'::jsonb, true, 4
);

