);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Nadie comprende este amor', 'nadie-comprende-este-amor', false, 'https://www.youtube.com/watch?v=uPMJFpics6o', 46, '[{"role":"llamada","text":"Nadie comprende que este amor se vive así,"},{"role":"coro","text":"por eso vengo!"},{"role":"llamada","text":"Yo te sigo a todos lados, siempre voy,"},{"role":"coro","text":"siempre te aliento."},{"role":"llamada","text":"Esta tarde no falles, Quito dame una alegría."},{"role":"coro","text":"La vuelta vamos a dar,"},{"role":"llamada","text":"si yo por vos daría la vida AKD."},{"role":"coro","text":"Vamo'' AKD,"},{"role":"llamada","text":"Vamo'', vamo'', vamo'', vamo'' AKD (x2)"},{"role":"coro","text":"Vamo'' la Academia (x2)"},{"role":"llamada","text":"Vamo'' la AKD (x2)"},{"role":"coro","text":"Vamo'' la Academia (x2)"}]'::jsonb, true, 7
);

