insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Quito ponga huevos', 'quito-ponga-huevos', false, 'https://www.youtube.com/watch?v=JUU1gjh_RVA', 55, '[{"role":"llamada","text":"Una banda que no le importa el decenso,"},{"role":"coro","text":"no me importa la mentira de los medios,"},{"role":"llamada","text":"alentamos en las buenas y en las malas,"},{"role":"coro","text":"vuelvo loco fumando la mar******."},{"role":"llamada","text":"Vamo'' la Academia!"},{"role":"coro","text":"Quito ponga huevos!"},{"role":"llamada","text":"Que este amor por vos es verdadero,"},{"role":"coro","text":"voy descontrolado con el Quito a todos lados,"},{"role":"llamada","text":"Quito, yo por vos, estoy llevado."}]'::jsonb, true, 9
