insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Quisiera ver a otros', 'quisiera-ver-a-otros', false, 'https://www.youtube.com/watch?v=Nh43hPa-5K4', 115, '[{"role":"llamada","text":"La AFE y la Ecuatoriana sobre la mesa,"},{"role":"coro","text":"dijeron que la Academia va a decender,"},{"role":"llamada","text":"la prensa quería que desaparecieras, (ni ver**)"},{"role":"coro","text":"ven esta hinchada y no lo pueden creer."},{"role":"llamada","text":"Yo quisiera ver a otros,"},{"role":"coro","text":"unos años en la B,"},{"role":"llamada","text":"y que tengan una banda como la de la AKD,"},{"role":"coro","text":"la que se aguanto la quiebra,"},{"role":"llamada","text":"el decenso y lo demás,"},{"role":"coro","text":"y aunque estemos en las malas,"},{"role":"llamada","text":"cada vez te quiero más."}]'::jsonb, true, 10
