insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Cómo no te voy a querer', 'como-no-te-voy-a-querer', true, 'https://www.youtube.com/watch?v=PMfczQKwrEk', 20, '[{"role":"llamada","text":"¿Cómo no te voy a querer?"},{"role":"coro","text":"¿Cómo no te voy a querer?"},{"role":"llamada","text":"si eres la Academis del fútbol"},{"role":"coro","text":"por eso nunca te dejaré."},{"role":"llamada","text":"---"},{"role":"coro","text":"Hay que salir campeón."},{"role":"llamada","text":"Hay que salir campeón."},{"role":"coro","text":"Vamo'' alentemos todos"},{"role":"llamada","text":"que este año vamos a salir campeón."}]'::jsonb, true, 11
