insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'La banda del Brujo presente', 'la-banda-del-brujo-presente', false, 'https://www.youtube.com/watch?v=4F_0xH9wPj8', 217, '[{"role":"llamada","text":"¿Cómo me voy a olvidar,"},{"role":"coro","text":"cuando en la Cocha dimos la vuelta?"},{"role":"llamada","text":"¿Cómo te vas a olvidar,"},{"role":"coro","text":"si te quedaste a ver toda la fiesta?"},{"role":"llamada","text":"Conociste un carnaval"},{"role":"coro","text":"cuando copamos tu gallinero,"},{"role":"llamada","text":"viste a esta hinchada alentar,"},{"role":"coro","text":"como tú nunca podrás hacerlo."},{"role":"llamada","text":"Ay qué dolor siente tu gente!"},{"role":"coro","text":"La banda del Brujo presente!!"},{"role":"llamada","text":"Una vez más, una vez más,"},{"role":"coro","text":"y a vos liguista, te vamo'' a reventar."}]'::jsonb, true, 13
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Y dale, Quito dale', 'y-dale-quito-dale', true, 'https://www.youtube.com/watch?v=hAFW26InC7w', 376, '[{"role":"llamada","text":"Y dale, y dale, y dale, Quito dale! (x2)"},{"role":"coro","text":"Sí, sí señores, yo soy del Quito,"},{"role":"llamada","text":"sí, sí señores, de corazón,"},{"role":"coro","text":"porque este año desde la plaza,"},{"role":"llamada","text":"desde la plaza,"},{"role":"coro","text":"saldrá el nuevo campeón."},{"role":"llamada","text":"---"},{"role":"coro","text":"Dale Quito, dale Quito,"},{"role":"llamada","text":"orgullo nacional,"},{"role":"coro","text":"Desde la plaza eres símbolo sexual,"},{"role":"llamada","text":"Noble la lucha con casta de campeón."},{"role":"coro","text":"Ejemplo de todo el continente,"},{"role":"llamada","text":"nuestra noble institución."},{"role":"coro","text":"Otra vez, ejemplo de todo el continente,"},{"role":"llamada","text":"nuestra noble institución."},{"role":"coro","text":"Y ahora estamos cantando fuerte,"},{"role":"llamada","text":"somos del Quito hasta la muerte"},{"role":"coro","text":"Y ahora estamos cantando fuerte,"},{"role":"llamada","text":"somos del Quito hasta la muerte"},{"role":"coro","text":"Hinchada, hinchada, hinchada hay una sola,"},{"role":"llamada","text":"hinchada la del Quito,"},{"role":"coro","text":"las demás son hij*******"},{"role":"llamada","text":"---"},{"role":"coro","text":"Yo te quiero AKD,"},{"role":"llamada","text":"a vos te sigo, vos sos mi vida."},{"role":"coro","text":"Siempre te voy a alentar,"},{"role":"llamada","text":"como lo hicimos cuando eras Argentina."},{"role":"coro","text":"Vayas a dónde vayas,"},{"role":"llamada","text":"esta es tu hinchada, la que te alienta."},{"role":"coro","text":"Vamos campeón, vamo'' a ganar,"},{"role":"llamada","text":"que la mafia está de fiesta!"},{"role":"coro","text":"Vamo'' campeón, hacélo por tu hinchada,"},{"role":"llamada","text":"la que te sigue en las buenas y en las malas,"},{"role":"coro","text":"vamo'' campeón, no falles a tu gente,"},{"role":"llamada","text":"no seas amargo como ese charameco."},{"role":"coro","text":"Yo soy así, al Quito yo lo quiero,"},{"role":"llamada","text":"vamo'' a cag**, UH, a todo el gallinero."}]'::jsonb, true, 14
);

