insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Si quieres ver fiesta', 'si-quieres-ver-fiesta', false, 'https://www.youtube.com/watch?v=TLCWF-6OSF0', 39, '[{"role":"llamada","text":"Si quieres ver fiesta,"},{"role":"coro","text":"saltá con la mafia"},{"role":"llamada","text":"porque ésta es la hinchada"},{"role":"coro","text":"más loca que hay."},{"role":"llamada","text":"Trajimos los trapos, "},{"role":"coro","text":"bombos y trompetas."},{"role":"llamada","text":"Todos los de liga se quieren matar."},{"role":"coro","text":"Vao'' la Academia, vamos a ganar"},{"role":"llamada","text":"que ésta es tu hinchada que te va a alentar."},{"role":"coro","text":"Vamo'' la Academia no podés perder"},{"role":"llamada","text":"porque a los de liga lo'' vamo'' a correr."}]'::jsonb, true, 22
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'La hinchada loca, la de la Academia', 'la-hinchada-loca-la-de-la-academia', false, 'https://www.youtube.com/watch?v=t0bWWDJJZgk', 43, '[{"role":"llamada","text":"Ésta es la hinchada loca, la de la Academia,"},{"role":"coro","text":"la que no abandona, y aguantó la quiebra."},{"role":"llamada","text":"Como fuimos al decenso nadie lo comprende,"},{"role":"coro","text":"junto a la azulgrana estaremos siempre."},{"role":"llamada","text":"En las malas vamo'' a estar,"},{"role":"coro","text":"ya lo vas a ver."},{"role":"llamada","text":"Se van a querer matar,"},{"role":"coro","text":"este año vamos a volver."},{"role":"llamada","text":"Le pido a todos los jugadores"},{"role":"coro","text":"que dejen la vida por estos colores."}]'::jsonb, true, 23
);

