insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Academia, hoy hay que ganar', 'academia-hoy-hay-que-ganar', false, 'https://www.youtube.com/watch?v=arUcsQnfhxI', 244, '[{"role":"llamada","text":"Academia, hoy hay que ganar,"},{"role":"coro","text":"a primera vamo'' a regresar,"},{"role":"llamada","text":"en las malasno te abandoné,"},{"role":"coro","text":"es la banda, la de la AKD."},{"role":"llamada","text":"Estuve en el decenso,"},{"role":"coro","text":"estaré donde sea,"},{"role":"llamada","text":"lo único que quiero es ver al Quito campeón,"},{"role":"coro","text":"otra vez en primera."}]'::jsonb, true, 25
