insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Vamo'' AKD, vamo'' a ganar', 'vamo-akd-vamo-a-ganar', false, 'https://www.youtube.com/watch?v=arUcsQnfhxI', 297, '[{"role":"llamada","text":"Mortero, la pu** que te pa***,"},{"role":"coro","text":"corriste con la banda del Brujo."},{"role":"llamada","text":"Mortero, no te vayas a olvidar,"},{"role":"coro","text":"que el Brujo va a ma*** al negro Paz."},{"role":"llamada","text":"Vamo'' AKD, vamo'' a ganar,"},{"role":"coro","text":"porque la vuelta vamo'' a dar,"},{"role":"llamada","text":"la hinchada está, nunca se fue,"},{"role":"coro","text":"aguante tiene la AKD"},{"role":"coro","text":"---"},{"role":"llamada","text":"Academia, te llevo en el corazón,"},{"role":"coro","text":"a la cancha, donde juegues, voy con vos,"},{"role":"llamada","text":"no me importa si perdés o si ganás,"},{"role":"coro","text":"Academia, cada vez te quiero más."},{"role":"llamada","text":"Vamo'' AKD, vamo'' a ganar,"},{"role":"coro","text":"porque la vuelta vamo'' a dar,"},{"role":"llamada","text":"la hinchada está, nunca se fue,"},{"role":"coro","text":"aguante tiene la AKD"}]'::jsonb, true, 26
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Y dale alegría a mi corazón', 'y-dale-alegria-a-mi-corazon', false, 'http://youtube.com/watch?v=yByZMHxuseE', 41, '[{"role":"llamada","text":"Y dale alegría, alegría a mi corazón,"},{"role":"coro","text":"después de 40 años salir campeón,"},{"role":"llamada","text":"en el decenso ésta banda no abandonó,"},{"role":"coro","text":"tenés que dejar el alma y el corazón."},{"role":"llamada","text":"Ya vas a ver"},{"role":"coro","text":"que de la mano de la mafia vamos a volver."},{"role":"llamada","text":"Y sí señor"},{"role":"coro","text":"ésta es la banda más loca del Ecuador."}]'::jsonb, true, 27
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'El vino y la dro**', 'el-vino-y', false, null, 0, '[{"role":"llamada","text":"El vino y la dro** me vuelan la mente,"},{"role":"coro","text":"yo vengo a alentarte con toda ésta gente,"},{"role":"llamada","text":"ganes o pierdas, ya no me interesa."},{"role":"coro","text":"Estamos re loco'', todo por la Academia."},{"role":"llamada","text":"Y vamo'' a ma*** a todos los de Liga,"},{"role":"coro","text":"(a vos hijue****)"},{"role":"llamada","text":"no te va a salvar ni la policía."},{"role":"coro","text":"El Brujo lo corre, gallina cagón"},{"role":"llamada","text":"que abran la 13, la banda ya llegó"},{"role":"coro","text":"dolor de cabeza alentando a la AKD,"},{"role":"llamada","text":"gallina coju** te vas para la B."}]'::jsonb, true, 28
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Ésta hinchada nunca te abandona', 'esta-hinchada-nunca-te-abandoana', false, 'https://www.youtube.com/watch?v=ZmzMgRzXHb8', 228, '[{"role":"llamada","text":"Ésta hinchada nunca te abandona,"},{"role":"coro","text":"somos de la Academia,"},{"role":"llamada","text":"no somos una moda."},{"role":"coro","text":"En cualquier cancha ponemos fiesta,"},{"role":"llamada","text":"vamos de la cabeza"},{"role":"coro","text":"la capital es nuestra."},{"role":"llamada","text":"Quito, te quiero"},{"role":"coro","text":"te sigo aunque no vayas primero."},{"role":"coro","text":"Quito, mi vida"},{"role":"llamada","text":"eres la razón de mis alegrías."}]'::jsonb, true, 29
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Borracho', 'borracho', false, 'https://www.youtube.com/watch?v=HAKpVXZJDYM', 291, '[{"role":"llamada","text":"Ponga huevos Academia que tenemos que ganar,"},{"role":"coro","text":"ésta banda está re loca,"},{"role":"llamada","text":"no te deja de alentar."},{"role":"coro","text":"No me importa el periodismo ni el derecho de admisión,"},{"role":"coro","text":"yo te sigo a todos lados,"},{"role":"llamada","text":"yo te quiero ver campeón."},{"role":"coro","text":"Borracho"},{"role":"llamada","text":"y delirando por volverte a ver,"},{"role":"coro","text":"la alegría la llevo en la piel,"},{"role":"llamada","text":"vamo'' vamo'' la AKD."}]'::jsonb, true, 30
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Muchos años aguantamos', 'mucho-aguantamos', true, 'https://www.youtube.com/watch?v=AaV2eQq59AY', 59, '[{"role":"llamada","text":"Muchos años aguantamos"},{"role":"coro","text":"las jodas y las cagadas"},{"role":"llamada","text":"que el Quito estaba en las malas,"},{"role":"coro","text":"que no da la vuelta a nada."},{"role":"coro","text":"Siempre estuve al frente"},{"role":"llamada","text":"con toda su gente"},{"role":"coro","text":"porque los resultados no apagaron esta fiebre."},{"role":"llamada","text":"Ya no dicen nada,"},{"role":"coro","text":"ya no se escucha nada,"},{"role":"llamada","text":"le cerramo'' el c*** a todas las hinchada."}]'::jsonb, true, 31
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Queremos la copa', 'queremos-la-copa', true, 'https://www.youtube.com/watch?v=Gp_b5TgLisg', 342, '[{"role":"llamada","text":"Vamo'' la AKD,"},{"role":"coro","text":"queremos la copa,"},{"role":"llamada","text":"tu hinchada está loca, Quito,"},{"role":"coro","text":"quiero verte campeón."},{"role":"coro","text":"Te venimos a ver como todos los años."},{"role":"llamada","text":"Ésta es mi ilusión"},{"role":"coro","text":"quiero verte campeón, Quito."}]'::jsonb, true, 32
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
