insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Vamo'' AKD', 'vamo-akd', true, 'https://www.youtube.com/watch?v=Nh43hPa-5K4', 187, '[{"role":"llamada","text":"[INTRO]"},{"role":"coro","text":"Vamo'' la Academia, vamo'', vamo'', vamo'', vamo'' la Academia. [x2]"},{"role":"llamada","text":"Vamo'' la AKD, AKD, Academia. [x2]"},{"role":"coro","text":"Vamo'' la AKD, AKD, AKD."},{"role":"llamada","text":"AKD! AKD! Vamo'' vamo la AKD! [x2]"},{"role":"coro","text":"---"},{"role":"coro","text":"Tenés que salir campeón, es este año,"},{"role":"llamada","text":"ustedes poniendo huevos y yo alentando,"},{"role":"coro","text":"porque te quiero tanto,"},{"role":"llamada","text":"otra vuelta yo quiero dar,"},{"role":"coro","text":"Academia este año no me puedes fallar."},{"role":"llamada","text":"Vamo'' AKD! [x4]"}]'::jsonb, false, 34
