insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Vamo'' vamo'' la azulgrana', 'vamo-vamo-la-azulgrana', false, 'https://www.youtube.com/watch?v=a6zHCQIsCgo', 244, '[{"role":"llamada","text":"Vamo'', vamo'' la azulgrana,"},{"role":"coro","text":"yo te sigo de la plaza,"},{"role":"llamada","text":"de cabeza a donde vayas,"},{"role":"coro","text":"en las buenas y en las malas."},{"role":"llamada","text":"Tu hinchada que vino descontrolada,"},{"role":"coro","text":"no te deja de alentar,"},{"role":"llamada","text":" hasta el final."},{"role":"coro","text":"Y a mí no me importa nada,"},{"role":"llamada","text":"si son todos noveleros,"},{"role":"coro","text":"son amargos los toreros,"},{"role":"llamada","text":"un velorio el astillero."},{"role":"coro","text":"fsdfsdfsdfsdf"},{"role":"llamada","text":"por amargo y por cagón."},{"role":"coro","text":"Vamo'' AKD, vamo'' a ganar,"},{"role":"llamada","text":"donde jugués yo voy a estar,"},{"role":"coro","text":"te alentaré de corazón,"},{"role":"llamada","text":"te quiero ver salir camepón."}]'::jsonb, false, 35
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Hoy es cuando más te amo', 'hoy-es-cuando-mas-te-amo', false, 'https://www.youtube.com/watch?v=H3lDCo3UZV0', 108, '[{"role":"llamada","text":"EWFWEFWEFWE"},{"role":"coro","text":"wefwefwfwefwe"},{"role":"llamada","text":"lo único que sigue intacto"},{"role":"coro","text":"es mi amor por ti."},{"role":"llamada","text":"Por las alegrías que pasamos"},{"role":"coro","text":"y por el amor que te juré,"},{"role":"llamada","text":"yo soy hincha de la AKD."},{"role":"coro","text":"Los huevos que tiene esta hinchada,"},{"role":"llamada","text":"esos pu*** los quieren tener."},{"role":"coro","text":"Hoy es cuando más te amo!"},{"role":"llamada","text":"En las malas estoy junto con vos,"},{"role":"coro","text":"por eso somos la más fiel,"},{"role":"llamada","text":"quiero morir aquí a tu lado"},{"role":"coro","text":"porque juntos vamos a volver."}]'::jsonb, false, 36
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'Azulgrana querido', 'azulgrana-querido', false, 'https://www.youtube.com/watch?v=94CkWZhnm8Q', 25, '[{"role":"llamada","text":"Somos de la gloriosa banda de la Academia,"},{"role":"coro","text":"psdfmsd,mgsdmfsdmf.s.d,fm.s"},{"role":"llamada","text":"Nsdfsdfsdfsdf"},{"role":"coro","text":"A pesar de los años y los malos presidentes"},{"role":"llamada","text":"sigo estando a tu lado, azulgrana querido"},{"role":"coro","text":"---"},{"role":"llamada","text":"Liga, Liga compadre, la con*** de tu ma*** (x2)"},{"role":"coro","text":"Siempre andan hablando, siempre andan diciendo."},{"role":"llamada","text":"cuando ven a la banda, salen todos corriendo."},{"role":"coro","text":"quiero volver a primera"},{"role":"coro","text":"y ser campeón nacional."},{"role":"llamada","text":"Tu hinchada"},{"role":"coro","text":"es la que siempre te viene a ver"},{"role":"llamada","text":"la que nunca te abandona"},{"role":"coro","text":"porque somos la más fiel."}]'::jsonb, false, 37
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'De pequeño te sigo', 'de-pequeno-te-sigo', false, 'https://www.youtube.com/watch?v=CSlY3jE5r5g', 29, '[{"role":"llamada","text":"De pequeño te sigo,"},{"role":"coro","text":"junto al Quito siempre a todo'' lado''"},{"role":"llamada","text":"Aguantamos las jodas,"},{"role":"coro","text":"los chantajes y 40 años."},{"role":"llamada","text":"No me olvido ese día,"},{"role":"coro","text":"los tara*** de enfrente decían"},{"role":"llamada","text":"que el Quito no existía, "},{"role":"coro","text":"que tenía que ser liquidado."},{"role":"llamada","text":"Si nos roban campeonatos ahí estamos (oh, oh)"},{"role":"coro","text":"aguantamos 4 decadas sin copa (oh, oh)"},{"role":"coro","text":"si la nuestra es una hinchada difenrete,"},{"role":"llamada","text":"no es amarga como los pu*** de enfrente (oh, oh)"},{"role":"coro","text":"pu** Méndez, De la Cruz y Saritama (oh, oh)"},{"role":"llamada","text":"se vendieron por unos cuantos centavos (oh, oh)"},{"role":"coro","text":"Y a vos Liga de Quito yo te digo:"},{"role":"llamada","text":"Ve, novelero, soy tu marido,"},{"role":"coro","text":"eres amargo y mal par***."}]'::jsonb, false, 38
);

insert into canticos (title, slug, classic, youtube_url, start_seconds, lines, published, order_index) values (
  'La banda del Brujo ya llegó', 'la-banda-del-brujo-ya-llego', true, 'https://www.youtube.com/watch?v=AaV2eQq59AY', 178, '[{"role":"llamada","text":"La banda del Brujo ya llegó para alentar"},{"role":"coro","text":"y en preferencia la fiesta va comenzar,"},{"role":"llamada","text":"no hay otra igual."},{"role":"coro","text":"Albo, Barcelona y Emelec "},{"role":"coro","text":"los quiero ver"},{"role":"llamada","text":"en un combate con el Brujo alguna vez,"},{"role":"coro","text":"pero sin correr."},{"role":"llamada","text":"Liga, vos que siempre para hablar no te aguantás"},{"role":"coro","text":"y con la banda del Brujo vas para atrás,"},{"role":"llamada","text":"¿por qué será?"}]'::jsonb, false, 39
);

